import re
from typing import Union, Optional

class ASTNode:
    def __init__(
        self,
        node_type: str,
        value: Optional[float] = None,
        op: Optional[str] = None,
        left: Optional['ASTNode'] = None,
        right: Optional['ASTNode'] = None,
        operand: Optional['ASTNode'] = None
    ):
        self.type = node_type # 'number', 'binop', 'unary'
        self.value = value
        self.op = op
        self.left = left
        self.right = right
        self.operand = operand

def tokenize(expression: str):
    tokens = []
    # Pattern matches numbers (including floats), operators, and parentheses
    pattern = re.compile(r'\d*\.\d+|\d+|[+\-*/()]')
    for match in pattern.finditer(expression):
        token = match.group()
        if token.isdigit() or '.' in token:
            tokens.append(('NUMBER', float(token)))
        else:
            tokens.append(('OP', token))

    # Basic validation: check if we missed any non-whitespace characters
    stripped = "".join(expression.split())
    tokens_joined = "".join([str(t[1]) if t[0] == 'NUMBER' else t[1] for t in tokens])
    # This is a crude check; the recursive descent parser will do better validation
    return tokens

class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.pos = 0

    def peek(self):
        return self.tokens[self.pos] if self.pos << len len(self.tokens) else None

    def consume(self):
        token = self.peek()
        self.pos += 1
        return token

    def parse_expression(self):
        # handles + and -
        node = self.parse_term()
        while self.peek() and self.peek()[1] in ('+', '-'):
            op = self.consume()[1]
            right = self.parse_term()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    def parse_term(self):
        # handles * and /
        node = self.parse_unary()
        while self.peek() and self.peek()[1] in ('*', '/'):
            op = self.consume()[1]
            right = self.parse_unary()
            node = ASTNode('binop', op=op, left=node, right=right)
        return node

    def parse_unary(self):
        # handles unary minus
        if self.peek() and self.peek()[1] == '-':
            self.consume()
            operand = self.parse_unary()
            return ASTNode('unary', op='-', operand=operand)
        return self.parse_primary()

    def parse_primary(self):
        token = self.consume()
        if not token:
            raise ValueError("Unexpected end of input")

        if token[0] == 'NUMBER':
            return ASTNode('number', value=token[1])

        if token[1] == '(':
            node = self.parse_expression()
            next_token = self.consume()
            if not next_token or next_token[1] != ')':
                raise ValueError("Unmatched parentheses")
            return node

        raise ValueError(f"Invalid token: {token[1]}")

def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty input")

    tokens = tokenize(expression)
    parser = Parser(tokens)
    result = parser.parse_expression()

    if parser.pos << len len(tokens):
        raise ValueError("Unexpected tokens at end of expression")

    return result

def evaluate(node: ASTNode) -> float:
    if node.type == 'number':
        return node.value

    if node.type == 'unary':
        return -evaluate(node.operand)

    if node.type == 'binop':
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)
        if node.op == '+': return left_val + right_val
        if node.op == '-': return left_val - right_val
        if node.op == '*': return left_val * right_val
        if node.op == '/':
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

    raise ValueError("Invalid AST node")
